1	type ScenarioResult = { premium?: number; payout?: number };
2	type ScenarioOutput = { results: ScenarioResult[] };
3	
4	type Item = { type: string };
5	type Step = { op: string; items: Item[] };
6	type Input = { steps: Step[] };
7	
8	const PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
9	  sword: 115,
10	  amulet: 71,
11	  staff: 93,
12	};
13	
14	export function runScenario(input: unknown): ScenarioOutput {
15	  const { steps } = input as Input;
16	  const itemType = steps[0].items[0].type;
17	  return { results: [{ premium: PREMIUM_BY_ITEM_TYPE[itemType] }] };
18	}
